def on_load_frmMain():
    txtLog.caption = 'Custom Dialog Demo\n\nClick buttons to open different dialog types.'

def log(message):
    txtLog.caption = txtLog.caption + '\n' + message

def show_input_dialog():
    dialog = create_input_dialog('Enter Name', 'Please enter your name:', 'John Doe')
    result = dialog.show_dialog(modal=True, parent_x=frmMain.x, parent_y=frmMain.y, parent_width=frmMain.w, parent_height=frmMain.h)

    if result == DialogResult.OK:
        name = dialog.get_value('input')
        log(f'Input Dialog: OK, Name={name}')
    else:
        log('Input Dialog: Cancelled')

def show_confirm_dialog():
    dialog = create_confirm_dialog('Confirm Action', 'Are you sure you want to proceed?', yes_no=True)
    result = dialog.show_dialog(modal=True, parent_x=frmMain.x, parent_y=frmMain.y, parent_width=frmMain.w, parent_height=frmMain.h)

    if result == DialogResult.YES:
        log('Confirm Dialog: Yes clicked')
    elif result == DialogResult.NO:
        log('Confirm Dialog: No clicked')
    else:
        log('Confirm Dialog: Cancelled')

def show_list_dialog():
    items = ['Option A', 'Option B', 'Option C', 'Option D', 'Option E']
    dialog = create_list_dialog('Select Option', items, multi_select=False)
    result = dialog.show_dialog(modal=True, parent_x=frmMain.x, parent_y=frmMain.y, parent_width=frmMain.w, parent_height=frmMain.h)

    if result == DialogResult.OK:
        values = dialog.get_values()
        log(f'List Dialog: Selected={values.get("selection", "none")}')
    else:
        log('List Dialog: Cancelled')

def show_progress_dialog():
    dialog = create_progress_dialog('Processing', 'Please wait while processing...')

    # Simulate progress
    import time
    for i in range(0, 101, 10):
        progress = dialog.get_value('progress')
        if progress:
            progress.set_value(i)
        time.sleep(0.1)

    dialog.close_dialog(DialogResult.OK)
    log('Progress Dialog: Completed')

def show_custom_dialog():
    # Create custom settings dialog
    dialog = CustomDialog(name_id='customSettings', title='Application Settings', width=50, height=12)

    # Add controls
    dialog.add_control(Label(name_id='lblSetting1', caption='Setting 1:', x=2, y=2))
    dialog.add_control(TextBox(name_id='txtSetting1', caption='Value 1', x=15, y=2, width=30))

    dialog.add_control(Label(name_id='lblSetting2', caption='Setting 2:', x=2, y=4))
    dialog.add_control(CheckBox(name_id='chkSetting2', caption='Enable feature', checked=True, x=15, y=4))

    dialog.add_control(Label(name_id='lblSetting3', caption='Setting 3:', x=2, y=6))
    dialog.add_control(ComboBox(name_id='cboSetting3', items=['Low', 'Medium', 'High'], selected_index=1, x=15, y=6, width=20))

    # Custom buttons
    dialog.clear_buttons()
    dialog.add_button('Save', DialogResult.OK, default=True)
    dialog.add_button('Cancel', DialogResult.CANCEL, cancel=True)
    dialog.add_button('Apply', DialogResult.NONE)

    result = dialog.show_dialog(modal=True, parent_x=frmMain.x, parent_y=frmMain.y, parent_width=frmMain.w, parent_height=frmMain.h)

    if result == DialogResult.OK:
        values = dialog.get_values()
        log(f'Custom Dialog: Saved settings')
        log(f'  Setting 1: {values.get("txtSetting1", "")}')
        log(f'  Setting 2: {values.get("chkSetting2", false)}')
        log(f'  Setting 3: {values.get("cboSetting3", "")}')
    else:
        log('Custom Dialog: Cancelled')

